mapper.select:
SELECT id, unit_name, unit_code, status, admin_user_id, create_time
FROM sys_org_unit
WHERE id = #{id}

SELECT id, unit_name, unit_code, status, admin_user_id, create_time
FROM sys_org_unit
WHERE unit_code = #{unitCode}

SELECT u.id, u.unit_name, u.unit_code, u.status, u.admin_user_id, admin.username AS admin_username, admin.real_name AS admin_real_name, u.create_time FROM sys_org_unit u LEFT JOIN sys_user admin ON admin.id = u.admin_user_id AND admin.is_deleted = FALSE WHERE u.id IN
#{unitId}
ORDER BY u.id DESC

mapper.update:
UPDATE sys_org_unit
SET unit_name = #{unitName},
    unit_code = #{unitCode},
    status = #{status},
    admin_user_id = #{adminUserId}
WHERE id = #{id}

UPDATE sys_unit
SET unit_name = #{unitName},
    unit_code = #{unitCode},
    status = #{status},
    admin_user_id = #{adminUserId}
WHERE id = #{id}

mapper.select:
SELECT COUNT(1)
FROM sys_org_node
WHERE unit_id = #{id}
